import React from "react";

export default function WhySection({ onOpenDemo }) {
  return (
    <section style={{ padding: 40, background: "#0b0b0b", color: "white" }}>
      <h2 style={{ fontSize: 36, marginTop: 0 }}>Why CineBridge</h2>
      <p style={{ opacity: 0.8 }}>Public film licensing redesigned for African cinema.</p>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, minmax(0, 1fr))", gap: 16, marginTop: 20 }}>
        <div style={{ border: "1px solid #333", borderRadius: 12, padding: 16 }}>Card 1</div>
        <div style={{ border: "1px solid #333", borderRadius: 12, padding: 16 }}>Card 2</div>
        <div style={{ border: "1px solid #333", borderRadius: 12, padding: 16 }}>Card 3</div>
      </div>

      <button
        onClick={onOpenDemo}
        style={{
          marginTop: 22,
          padding: "14px 18px",
          borderRadius: 10,
          border: 0,
          background: "#f08a1a",
          color: "white",
          fontWeight: 700,
          cursor: "pointer",
        }}
      >
        ▶ Download Demo Film
      </button>
    </section>
  );
}
